package com.schwab.urlShortener.ratelimit;

public class RateLimitExceededException extends RuntimeException {
    private final String ipAddress;

    public RateLimitExceededException(String ipAddress) {
        super("Rate limit exceeded for IP: " + ipAddress);
        this.ipAddress = ipAddress;
    }

    public String getIpAddress() {
        return ipAddress;
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.exception.InvalidUrlException;
import com.schwab.urlShortener.exception.ShortCodeGenerationException;
import com.schwab.urlShortener.exception.ShortLinkNotFoundException;
import com.schwab.urlShortener.ratelimit.RateLimitExceededException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.net.URI;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ShortLinkNotFoundException.class)
    public ProblemDetail handleShortLinkNotFound(ShortLinkNotFoundException ex) {
        logger.debug("Short link not found: {}", ex.getMessage());
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.NOT_FOUND,
            ex.getMessage()
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/short-link-not-found"));
        problemDetail.setTitle("Short Link Not Found");
        return problemDetail;
    }

    @ExceptionHandler(InvalidUrlException.class)
    public ProblemDetail handleInvalidUrl(InvalidUrlException ex) {
        logger.debug("Invalid URL provided: {}", ex.getMessage());
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.BAD_REQUEST,
            ex.getMessage()
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/invalid-url"));
        problemDetail.setTitle("Invalid URL");
        return problemDetail;
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail handleValidationErrors(MethodArgumentNotValidException ex) {
        logger.debug("Validation error: {}", ex.getMessage());
        String detail = ex.getBindingResult().getFieldErrors().stream()
            .map(error -> error.getField() + ": " + error.getDefaultMessage())
            .reduce((a, b) -> a + "; " + b)
            .orElse("Validation failed");

        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.BAD_REQUEST,
            detail
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/validation-error"));
        problemDetail.setTitle("Validation Error");
        return problemDetail;
    }

    @ExceptionHandler(ShortCodeGenerationException.class)
    public ProblemDetail handleShortCodeGeneration(ShortCodeGenerationException ex) {
        logger.error("Failed to generate short code: {}", ex.getMessage());
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.INTERNAL_SERVER_ERROR,
            "Failed to generate a unique short code. Please try again."
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/short-code-generation-failed"));
        problemDetail.setTitle("Short Code Generation Failed");
        return problemDetail;
    }

    @ExceptionHandler(HttpMessageNotReadableException.class)
    public ProblemDetail handleHttpMessageNotReadable(HttpMessageNotReadableException ex) {
        logger.debug("Malformed JSON request: {}", ex.getMessage());
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.BAD_REQUEST,
            "Malformed JSON request"
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/malformed-request"));
        problemDetail.setTitle("Malformed Request");
        return problemDetail;
    }

    @ExceptionHandler(RateLimitExceededException.class)
    public ProblemDetail handleRateLimitExceeded(RateLimitExceededException ex) {
        logger.debug("Rate limit exceeded: {}", ex.getMessage());
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
            HttpStatus.TOO_MANY_REQUESTS,
            ex.getMessage()
        );
        problemDetail.setType(URI.create("https://api.schwab.com/problems/rate-limit-exceeded"));
        problemDetail.setTitle("Rate Limit Exceeded");
        return problemDetail;
    }
}

package com.schwab.urlShortener.ratelimit;

import jakarta.servlet.http.HttpServletRequest;
import org.springframework.stereotype.Component;

@Component
public class IpExtractor {

    public String extractIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");

        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            String[] ips = xForwardedFor.split(",");
            return ips[0].trim();
        }

        String xRealIp = request.getHeader("X-Real-IP");
        if (xRealIp != null && !xRealIp.isEmpty()) {
            return xRealIp.trim();
        }

        return request.getRemoteAddr();
    }
}

package com.schwab.urlShortener.ratelimit;

public interface RateLimiter {
    void checkRateLimit(String ipAddress) throws RateLimitExceededException;
}

package com.schwab.urlShortener.ratelimit;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class InMemoryRateLimiter implements RateLimiter {

    private final int requestsPerWindow;
    private final long windowDurationSeconds;
    private final ConcurrentHashMap<String, TokenBucket> buckets;

    public InMemoryRateLimiter(
            @Value("${ratelimit.requests-per-window:60}") int requestsPerWindow,
            @Value("${ratelimit.window-duration-seconds:60}") long windowDurationSeconds) {
        this.requestsPerWindow = requestsPerWindow;
        this.windowDurationSeconds = windowDurationSeconds;
        this.buckets = new ConcurrentHashMap<>();
    }

    @Override
    public void checkRateLimit(String ipAddress) throws RateLimitExceededException {
        TokenBucket bucket = buckets.compute(ipAddress, (key, existing) -> {
            if (existing == null) {
                return new TokenBucket(requestsPerWindow, windowDurationSeconds);
            }
            return existing;
        });

        if (!bucket.tryConsume()) {
            throw new RateLimitExceededException(ipAddress);
        }
    }

    private static class TokenBucket {
        private final int capacity;
        private final long windowDurationSeconds;
        private int tokens;
        private long windowStart;

        TokenBucket(int capacity, long windowDurationSeconds) {
            this.capacity = capacity;
            this.windowDurationSeconds = windowDurationSeconds;
            this.tokens = capacity;
            this.windowStart = Instant.now().getEpochSecond();
        }

        synchronized boolean tryConsume() {
            long now = Instant.now().getEpochSecond();

            if (now - windowStart >= windowDurationSeconds) {
                tokens = capacity;
                windowStart = now;
            }

            if (tokens > 0) {
                tokens--;
                return true;
            }

            return false;
        }
    }
}

package com.schwab.urlShortener.ratelimit;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

@Component
@Order(1)
public class RateLimitFilter extends OncePerRequestFilter {

    private final IpExtractor ipExtractor;
    private final RateLimiter rateLimiter;

    public RateLimitFilter(IpExtractor ipExtractor, RateLimiter rateLimiter) {
        this.ipExtractor = ipExtractor;
        this.rateLimiter = rateLimiter;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        if (shouldRateLimit(request)) {
            String ipAddress = ipExtractor.extractIp(request);
            rateLimiter.checkRateLimit(ipAddress);
        }

        filterChain.doFilter(request, response);
    }

    private boolean shouldRateLimit(HttpServletRequest request) {
        return "POST".equalsIgnoreCase(request.getMethod()) 
            && request.getRequestURI().startsWith("/api/v1/links");
    }
}

package com.schwab.urlShortener.ratelimit;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class InMemoryRateLimiterTest {

    private InMemoryRateLimiter rateLimiter;

    @BeforeEach
    void setUp() {
        rateLimiter = new InMemoryRateLimiter(5, 1);
    }

    @Test
    void allowsRequestsWithinLimit() {
        String ip = "192.168.1.1";

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip);
        }

        // No exception thrown means all requests were allowed
    }

    @Test
    void throwsExceptionWhenLimitExceeded() {
        String ip = "192.168.1.2";

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip);
        }

        assertThatThrownBy(() -> rateLimiter.checkRateLimit(ip))
            .isInstanceOf(RateLimitExceededException.class)
            .hasMessageContaining("192.168.1.2");
    }

    @Test
    void resetsTokensAfterWindowExpires() throws InterruptedException {
        String ip = "192.168.1.3";

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip);
        }

        assertThatThrownBy(() -> rateLimiter.checkRateLimit(ip))
            .isInstanceOf(RateLimitExceededException.class);

        Thread.sleep(1100);

        rateLimiter.checkRateLimit(ip);
        // No exception after window reset
    }

    @Test
    void tracksLimitsIndependentlyPerIp() {
        String ip1 = "192.168.1.4";
        String ip2 = "192.168.1.5";

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip1);
        }

        assertThatThrownBy(() -> rateLimiter.checkRateLimit(ip1))
            .isInstanceOf(RateLimitExceededException.class);

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip2);
        }
        // ip2 has its own limit
    }

    @Test
    void handlesZeroRequestsPerWindow() {
        InMemoryRateLimiter restrictiveRateLimiter = new InMemoryRateLimiter(0, 60);
        String ip = "192.168.1.6";

        assertThatThrownBy(() -> restrictiveRateLimiter.checkRateLimit(ip))
            .isInstanceOf(RateLimitExceededException.class);
    }

    @Test
    void handlesConcurrentRequestsFromSameIp() throws InterruptedException {
        String ip = "192.168.1.7";
        int threadCount = 10;
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
        CountDownLatch latch = new CountDownLatch(threadCount);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failureCount = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            executor.submit(() -> {
                try {
                    rateLimiter.checkRateLimit(ip);
                    successCount.incrementAndGet();
                } catch (RateLimitExceededException e) {
                    failureCount.incrementAndGet();
                } finally {
                    latch.countDown();
                }
            });
        }

        latch.await(5, TimeUnit.SECONDS);
        executor.shutdown();

        assertThat(successCount.get()).isEqualTo(5);
        assertThat(failureCount.get()).isEqualTo(5);
    }

    @Test
    void allowsFullCapacityInEachNewWindow() throws InterruptedException {
        String ip = "192.168.1.8";

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip);
        }

        Thread.sleep(1100);

        for (int i = 0; i < 5; i++) {
            rateLimiter.checkRateLimit(ip);
        }
        // All 5 requests in new window should succeed
    }

    @Test
    void usesDefaultConfigurationWhenNotProvided() {
        InMemoryRateLimiter defaultRateLimiter = new InMemoryRateLimiter(60, 60);
        String ip = "192.168.1.9";

        for (int i = 0; i < 60; i++) {
            defaultRateLimiter.checkRateLimit(ip);
        }

        assertThatThrownBy(() -> defaultRateLimiter.checkRateLimit(ip))
            .isInstanceOf(RateLimitExceededException.class);
    }
}

package com.schwab.urlShortener.ratelimit;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;

import java.io.IOException;

import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class RateLimitFilterTest {

    @Mock
    private IpExtractor ipExtractor;

    @Mock
    private RateLimiter rateLimiter;

    @Mock
    private FilterChain filterChain;

    @InjectMocks
    private RateLimitFilter rateLimitFilter;

    @Test
    void appliesRateLimitingToPostLinksEndpoint() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("POST");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        when(ipExtractor.extractIp(request)).thenReturn("192.168.1.1");

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor).extractIp(request);
        verify(rateLimiter).checkRateLimit("192.168.1.1");
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void doesNotApplyRateLimitingToGetRequests() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("GET");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor, never()).extractIp(any());
        verify(rateLimiter, never()).checkRateLimit(any());
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void doesNotApplyRateLimitingToDifferentEndpoint() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("POST");
        request.setRequestURI("/api/v1/other");
        MockHttpServletResponse response = new MockHttpServletResponse();

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor, never()).extractIp(any());
        verify(rateLimiter, never()).checkRateLimit(any());
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void appliesRateLimitingToSubpathsOfLinksEndpoint() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("POST");
        request.setRequestURI("/api/v1/links/something");
        MockHttpServletResponse response = new MockHttpServletResponse();

        when(ipExtractor.extractIp(request)).thenReturn("192.168.1.2");

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor).extractIp(request);
        verify(rateLimiter).checkRateLimit("192.168.1.2");
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void propagatesRateLimitExceededException() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("POST");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        when(ipExtractor.extractIp(request)).thenReturn("192.168.1.3");
        doThrow(new RateLimitExceededException("192.168.1.3"))
            .when(rateLimiter).checkRateLimit("192.168.1.3");

        assertThatThrownBy(() -> rateLimitFilter.doFilterInternal(request, response, filterChain))
            .isInstanceOf(RateLimitExceededException.class)
            .hasMessageContaining("192.168.1.3");

        verify(filterChain, never()).doFilter(any(), any());
    }

    @Test
    void caseInsensitiveMethodMatching() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("post");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        when(ipExtractor.extractIp(request)).thenReturn("192.168.1.4");

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor).extractIp(request);
        verify(rateLimiter).checkRateLimit("192.168.1.4");
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void doesNotApplyRateLimitingToPutRequests() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("PUT");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor, never()).extractIp(any());
        verify(rateLimiter, never()).checkRateLimit(any());
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void doesNotApplyRateLimitingToDeleteRequests() throws ServletException, IOException {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setMethod("DELETE");
        request.setRequestURI("/api/v1/links");
        MockHttpServletResponse response = new MockHttpServletResponse();

        rateLimitFilter.doFilterInternal(request, response, filterChain);

        verify(ipExtractor, never()).extractIp(any());
        verify(rateLimiter, never()).checkRateLimit(any());
        verify(filterChain).doFilter(request, response);
    }
}
